Rule.Source:
import java.util.List;
import java.util.ArrayList;

logger.trace("Entry Rule:: Validate Access Request");
logger.trace("requestor: "+requestor);
logger.trace("selectedIdentities: "+selectedIdentities);
logger.trace("addedItems: "+addedItems);
logger.trace("removedItems: "+removedItems);

logger.trace("Starting validation");

//Do not modify
List validationErrors = new ArrayList();
if(addedItems==void){
  addedItems=new ArrayList();
}
if(removedItems==void){
  removedItems=new ArrayList();
}
//

//Custom Validation
validationErrors.add("Custom Validation Message");

logger.trace("Finishing validation");
logger.trace("Exit Rule:: Validate Access Request");

return validationErrors;
